final:
module RefModule (
    input clk,
    input rst,
    output reg [3:0] gray
);
    reg [3:0] obf_binary;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            obf_binary <= 4'b0000;
            gray <= 4'b0000;
        end else begin
            obf_binary <= obf_binary + 1;
            gray <= (obf_binary >> 1) ^ obf_binary;
        end
    end
endmodule
